const config = $input.first().json;
const query = encodeURIComponent(config.location + ' ' + config.searchQuery);
const url = 'https://www.google.com/maps/search/' + query;
return {
  json: {
    ...config,
    mapsUrl: url
  }
};

const html = $input.first().json.data || '';
const config = $('Search Config').first().json;

// Extract website URLs from Google Maps HTML
const urlRegex = /https?:\/\/[^\/\s"'>]+/g;
const allUrls = html.match(urlRegex) || [];

// Filter out Google/system domains
const blockedDomains = ['google', 'gstatic', 'googleapis', 'schema', 'ggpht', 'youtube', 'goo.gl'];
const validUrls = [...new Set(allUrls)].filter(url => {
  const lower = url.toLowerCase();
  return !blockedDomains.some(d => lower.includes(d));
});

// Try to extract business names from Maps HTML
// Google Maps embeds business data in various patterns
const nameRegex = /\["([^"]{3,60})"(?:,null){0,3},"https?:\/\//g;
const names = [];
let nameMatch;
while ((nameMatch = nameRegex.exec(html)) !== null) {
  names.push(nameMatch[1]);
}

// Try to extract addresses
const addressRegex = /\["(\d+[^"]{5,80}(?:St|Street|Ave|Avenue|Rd|Road|Dr|Drive|Blvd|Way|Lane|Ln|Ct|Pl)[^"]{0,40})"/gi;
const addresses = [];
let addrMatch;
while ((addrMatch = addressRegex.exec(html)) !== null) {
  addresses.push(addrMatch[1]);
}

// Try to extract phone numbers from Maps data
const phoneRegex = /(?:\+\d{1,3}[\s.-]?)?\(?\d{2,4}\)?[\s.-]?\d{3,4}[\s.-]?\d{3,4}/g;
const phones = [...new Set((html.match(phoneRegex) || []))];

// Try to extract ratings
const ratingRegex = /\[(\d\.\d),"\d+ review/g;
const ratings = [];
let rateMatch;
while ((rateMatch = ratingRegex.exec(html)) !== null) {
  ratings.push(parseFloat(rateMatch[1]));
}

// Build business objects - match URLs with any extracted metadata
const maxResults = parseInt(config.maxResults) || 50;
const businesses = validUrls.slice(0, maxResults).map((url, i) => ({
  businessName: names[i] || '',
  website: url.split('/').slice(0, 3).join('/'),
  address: addresses[i] || '',
  phone: phones[i] || '',
  rating: ratings[i] || 0,
  industry: config.searchQuery,
  location: config.location
}));

if (businesses.length === 0) {
  return [{ json: { error: 'No businesses found', urlCount: allUrls.length } }];
}

return businesses.map(b => ({ json: b }));

const html = $input.first().json.data || $input.first().json.body || '';
const original = $('Loop Over Businesses').item.json;

// Email extraction (exclude image extensions)
const emailRegex = /[a-zA-Z0-9._%+-]+@[a-zA-Z0-9.-]+\.(?!jpeg|jpg|png|gif|webp|svg|css|js)[a-zA-Z]{2,}/g;
const rawEmails = html.match(emailRegex) || [];
const emails = [...new Set(rawEmails.map(e => e.toLowerCase()))];

// Phone extraction
const phoneRegex = /(?:\+\d{1,3}[\s.-]?)?\(?\d{2,4}\)?[\s.-]?\d{3,4}[\s.-]?\d{3,4}/g;
const rawPhones = html.match(phoneRegex) || [];
const phones = [...new Set(rawPhones)].filter(p => p.replace(/\D/g, '').length >= 7);

// Social media extraction
const linkedinRegex = /https?:\/\/(?:www\.)?linkedin\.com\/(?:company|in)\/[^\s"'<>)]+/gi;
const facebookRegex = /https?:\/\/(?:www\.)?facebook\.com\/[^\s"'<>)]+/gi;
const instagramRegex = /https?:\/\/(?:www\.)?instagram\.com\/[^\s"'<>)]+/gi;

const linkedin = (html.match(linkedinRegex) || [])[0] || '';
const facebook = (html.match(facebookRegex) || [])[0] || '';
const instagram = (html.match(instagramRegex) || [])[0] || '';

// Merge with original business data
const result = {
  businessName: original.businessName || '',
  website: original.website || '',
  address: original.address || '',
  phone: phones[0] || original.phone || '',
  rating: original.rating || 0,
  industry: original.industry || '',
  location: original.location || '',
  emails: emails,
  linkedin: linkedin,
  facebook: facebook,
  instagram: instagram
};

return { json: result };

const items = $input.all();
const seen = new Set();
const results = [];

for (const item of items) {
  const email = (item.json.emails || '').toString().toLowerCase().trim();
  if (!email || seen.has(email)) continue;
  seen.add(email);

  // Calculate lead score (0-100)
  let score = 0;
  if (email) score += 20;
  if (item.json.phone) score += 15;
  if (item.json.businessName) score += 15;
  if (item.json.address) score += 10;
  if (item.json.rating > 0) score += 10;
  if (item.json.linkedin || item.json.facebook || item.json.instagram) score += 10;
  if (item.json.website) score += 10;
  if (item.json.phone && email) score += 10; // bonus for multiple contact methods

  results.push({
    json: {
      ...item.json,
      email: email,
      leadScore: score,
      status: 'New',
      source: 'Google Maps Scraper',
      datescraped: new Date().toISOString().split('T')[0]
    }
  });
}

return results.length > 0 ? results : [{ json: { _empty: true } }];

const input = $input.first().json;
const leadData = $('Score Leads').item.json;
const config = $('Search Config').first().json;

// Parse AI response - chainLlm returns text in 'text' field
let emailContent;
try {
  const rawText = input.text || input.response || JSON.stringify(input);
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  emailContent = JSON.parse(jsonMatch[0]);
} catch (e) {
  emailContent = {
    subject: 'Partnership opportunity for ' + (leadData.businessName || 'your business'),
    body: 'I noticed ' + (leadData.businessName || 'your business') + ' in ' + leadData.location + ' and wanted to reach out about a potential collaboration that could benefit your ' + leadData.industry + ' practice.',
    cta_text: 'Would a brief 10-minute call this week work to explore this?'
  };
}

const htmlBody = '<div style="font-family:Segoe UI,Arial,sans-serif;max-width:600px;margin:0 auto;background:#fff;">' +
  '<div style="padding:30px 40px 20px;border-bottom:3px solid #FF6D5A;">' +
  '<h1 style="margin:0;font-size:22px;color:#1A1A2E;">' + config.senderCompany + '</h1></div>' +
  '<div style="padding:30px 40px;">' +
  '<p style="font-size:15px;line-height:1.6;color:#333;">' + emailContent.body + '</p>' +
  '<p style="font-size:15px;line-height:1.6;color:#333;">' + emailContent.cta_text + '</p>' +
  '<p style="font-size:15px;line-height:1.6;color:#333;margin-top:24px;">Best regards,<br>' +
  '<strong>' + config.senderName + '</strong><br>' +
  '<span style="color:#666;">' + config.senderTitle + '</span><br>' +
  '<span style="color:#666;">' + config.senderCompany + '</span></p></div>' +
  '<div style="padding:20px 40px;background:#f8f8f8;border-top:1px solid #eee;">' +
  '<p style="font-size:11px;color:#999;">You received this because your business was listed publicly on Google Maps. Reply &quot;unsubscribe&quot; to be removed.</p></div></div>';

return {
  json: {
    to: leadData.email,
    subject: emailContent.subject,
    htmlBody: htmlBody,
    leadEmail: leadData.email,
    businessName: leadData.businessName
  }
};

const items = $('Score Leads').all();
const config = $('Search Config').first().json;

const totalLeads = items.filter(i => !i.json._empty).length;
const avgScore = totalLeads > 0
  ? Math.round(items.reduce((sum, i) => sum + (i.json.leadScore || 0), 0) / totalLeads)
  : 0;

const now = new Date().toLocaleString('en-ZA', { timeZone: 'Africa/Johannesburg' });

return {
  json: {
    subject: `Lead Scraper Complete: ${totalLeads} leads found`,
    body: [
      `<h2>Lead Scraper Run Complete</h2>`,
      `<p><strong>Date:</strong> ${now}</p>`,
      `<p><strong>Search:</strong> ${config.searchQuery} in ${config.location}</p>`,
      `<hr>`,
      `<p><strong>Total Leads Found:</strong> ${totalLeads}</p>`,
      `<p><strong>Average Lead Score:</strong> ${avgScore}/100</p>`,
      `<hr>`,
      `<p>Check your <a href="https://airtable.com/${'appzcZpiIZ6QPtJXT'">Airtable CRM</a> for details.</p>`
    ].join('\n')
  }
};

